1	/**
2	 * run_policy.js — run YOUR policy and print metrics. Episodes play until you win, die, or
3	 * reach the step budget (default 90k, extendable via --max_steps).
4	 *
5	 * Usage:
6	 *   node run_policy.js                       # ./policy.js on seed 1 (the default)
7	 *   node run_policy.js --seeds 1,2,3         # play these seeds (you choose how many)
8	 *   node run_policy.js --policy ./policy.js  # explicit policy file
9	 *   node run_policy.js --speed_cap 40 --frame_skip 1   # speed_cap default is 40 px/tick; "inf"=uncapped
10	 *   node run_policy.js --max_steps 8000      # OPTIONAL: cap a run for fast iteration
11	 *   node run_policy.js --log light|full|none # per-game log level (default: light)
12	 *   node run_policy.js --trace trace.jsonl   # (debug) dump a per-step JSONL trace inline
13	 *   node run_policy.js --json                # machine-readable output only
14	 *
15	 * PER-GAME LOGS: every game you play is auto-saved (default `light`) to game_logs/ —
16	 * a small, fully replayable record { seed, config, action_log, checkpoints, game_version }.
17	 * Kept in memory and written once at the end (no per-step I/O). `--log full` also embeds the
18	 * per-step trace; `--log none` disables it. Regenerate a full trace from a light log with
19	 * `node expand_trace.js game_logs/<file>`. Filenames are conflict-safe (seed + run token).
20	 *
21	 * Your policy.js must export { init?(), policy(obs, mem) -> { action, mem } }.
22	 * See INTERFACE.md §6 for the contract and GAME_DESCRIPTION.md for the goal.
23	 *
24	 * SEEDS: by default you play one seed (1). You may choose to practise on more
25	 * (--seeds 1,2,3) — your call; you don't have to. Your final policy is also checked on
26	 * a separate, held-out set of seeds you don't see, so prefer robust play over fitting
27	 * one seed. Default step budget is 90k (the game ends on win/death, or at the budget); pass a
28	 * LARGER --max_steps to extend (a slow grind may need it), or a smaller one to cut runs short.
29	 */
30	"use strict";
31	
32	const fs = require("fs");
33	const path = require("path");
34	const crypto = require("crypto");
35	const { RogueEnv } = require("./env.bundle.js");
36	
37	// Default seed when you don't pass --seeds (you choose to add more if you want).
38	const DEFAULT_SEEDS = [1];
39	// Other seeds available to practise on if you choose (held-out seeds are NOT here).
40	const TRAINING_SEEDS = [11, 23, 42, 57, 88, 101, 137, 199, 256, 314, 451, 512];
41	
42	function runEpisode(env, policyMod, seed, config, opts = {}) {
43	  const onStep = typeof opts === "function" ? opts : opts.onStep; // back-compat
44	  const captureLight = !!(opts && opts.captureLight);
45	  const captureFull = !!(opts && opts.captureFull);
46	  let mem = typeof policyMod.init === "function" ? policyMod.init() : {};
47	  let { obs } = env.reset(seed, config);
48	  const field = obs.field;
49	  const events = {};
50	  const action_log = [];   // LIGHT: kept in memory, dumped once at the end (no per-step I/O)
51	  const checkpoints = [];  // periodic obs hashes to verify a replay reproduces the game
52	  const full = [];         // FULL: per-step obs/reward (big) — only when captureFull
53	  let steps = 0;
54	  let last = { obs, reward_info: obs.reward_info, event: null, done: false };
55	  const cap = (config.max_steps || 90000) + 5; // step-budget backstop; games end on win/death/budget
56	  while (steps < cap) {
57	    let out;
58	    try {
59	      out = policyMod.policy(last.obs, mem);
60	    } catch (e) {
61	      return Object.assign({ seed, steps, policy_error: String((e && e.message) || e) }, last.reward_info);
62	    }
63	    const action = (out && out.action) || { move: [0, 0], upgrade_choice: 0 };
64	    mem = out && "mem" in out ? out.mem : mem;
65	    last = env.step(action);
66	    steps += 1;
67	    if (captureLight) {
68	      action_log.push(action);
69	      if (steps % 600 === 0) checkpoints.push({ step: steps, obs_hash: hashObs(last.obs) });
70	    }
71	    if (captureFull) full.push({ step: steps, action, obs: last.obs, reward_info: last.reward_info, event: last.event, done: last.done });
72	    if (last.event) events[last.event.kind] = (events[last.event.kind] || 0) + 1;
73	    if (onStep) onStep({ step: steps, action, obs: last.obs, reward_info: last.reward_info, event: last.event, done: last.done });
74	    if (last.done) break;
75	  }
76	  const result = Object.assign({ seed, steps, events }, last.reward_info);
77	  if (captureLight) result._gamelog = { field, action_log, checkpoints, full: captureFull ? full : null };
78	  return result;
79	}
80	
81	function hashObs(obs) {
82	  return crypto.createHash("sha1").update(JSON.stringify(obs)).digest("hex").slice(0, 12);
83	}
84	
85	/** sha1 of the env bundle — the "game version" that a light log replays against. */
86	function bundleVersion() {
87	  try {
88	    return crypto.createHash("sha1").update(fs.readFileSync(path.join(__dirname, "env.bundle.js"))).digest("hex").slice(0, 12);
89	  } catch (e) { return "unknown"; }
90	}
91	
92	/**
93	 * Write one game's log. LIGHT = {seed, config, action_log, checkpoints, version} —
94	 * small and fully replayable (re-run action_log on seed to regenerate everything;
95	 * see expand_trace.js). FULL also embeds the per-step trace. Conflict-safe filename:
96	 * seed + a per-process run token + a per-game index, so concurrent/repeat runs never
97	 * clobber each other.
98	 */
99	function writeGameLog(result, config, gameVersion, level, dir, runToken, idx) {
100	  const gl = result._gamelog;
101	  if (!gl) return null;
102	  const out = {
103	    format: "rogue_game_trace_v1",
104	    level,
105	    game_version: gameVersion,
106	    seed: result.seed,
107	    config: {
108	      speed_cap: config.speed_cap === Infinity ? "inf" : config.speed_cap,
109	      frame_skip: config.frame_skip,
110	      max_steps: config.max_steps,
111	      character_id: config.character_id,
112	      field: gl.field,
113	    },
114	    reward_info: {
115	      progress: result.progress, score: result.score, wave: result.wave, level: result.level,
116	      kills: result.kills, boss_reached: result.boss_reached, boss_cleared: result.boss_cleared,
117	      survived_ms: result.survived_ms, done_reason: result.done_reason,
118	    },
119	    checkpoints: gl.checkpoints,
120	    action_log: gl.action_log,
121	  };
122	  if (level === "full" && gl.full) out.full = gl.full;
123	  fs.mkdirSync(dir, { recursive: true });
124	  const fname = `game_s${result.seed}_${runToken}_${String(idx).padStart(3, "0")}.json`;
125	  const full = path.join(dir, fname);
126	  fs.writeFileSync(full, JSON.stringify(out));
127	  return full;
128	}
129	
130	function aggregate(results) {
131	  const fields = ["progress", "score", "survived_ms", "kills", "level", "wave"];
132	  const agg = { n: results.length };
133	  for (const f of fields) {
134	    const v = results.map((r) => Number(r[f]) || 0).sort((a, b) => a - b);
135	    const sum = v.reduce((a, b) => a + b, 0);
136	    agg[f] = { mean: round2(sum / v.length), median: v[Math.floor((v.length - 1) / 2)], min: v[0], max: v[v.length - 1] };
137	  }
138	  const rate = (p) => round2(results.filter(p).length / Math.max(1, results.length));
139	  agg.boss_reached_rate = rate((r) => r.boss_reached);
140	  agg.boss_cleared_rate = rate((r) => r.boss_cleared);
141	  agg.death_rate = rate((r) => r.done_reason === "death");
142	  agg.timeout_rate = rate((r) => r.done_reason === "timeout");
143	  return agg;
144	}
145	
146	function round2(v) { return Math.round(v * 100) / 100; }
147	
148	function parseSeeds(spec) {
149	  if (!spec) return DEFAULT_SEEDS.slice();
150	  const out = [];
151	  for (const part of String(spec).split(",")) {
152	    const m = part.match(/^(-?\d+)\.\.(-?\d+)$/);
153	    if (m) { for (let i = +m[1]; i <= +m[2]; i += 1) out.push(i); }
154	    else if (part.trim() !== "") out.push(Number(part));
155	  }
156	  return out;
157	}
158	
159	function parseArgs(argv) {
160	  const a = { policy: "./policy.js", seeds: "", speed_cap: "40", frame_skip: "1", max_steps: "0", character: "striker", trace: null, json: false, log: "light", "log-dir": "game_logs" };
161	  for (let i = 2; i < argv.length; i += 1) {
162	    const k = argv[i];
163	    if (k === "--json") { a.json = true; continue; }
164	    if (k === "--help" || k === "-h") { a.help = true; continue; }
165	    if (k.startsWith("--")) { a[k.slice(2)] = argv[i + 1]; i += 1; }
166	  }
167	  return a;
168	}
169	
170	if (require.main === module) {
171	  const a = parseArgs(process.argv);
172	  if (a.help) {
173	    console.log(fs.readFileSync(__filename, "utf8").split("*/")[0].replace(/^\/\*+/, "").trim());
174	    process.exit(0);
175	  }
176	  const config = {
177	    speed_cap: a.speed_cap === "inf" ? Infinity : Number(a.speed_cap),
178	    frame_skip: parseInt(a.frame_skip, 10) || 1,
179	    max_steps: parseInt(a.max_steps, 10) || 90000, // default budget 90k; --max_steps N to extend/cut short
180	    character_id: a.character,
181	  };
182	  const seeds = parseSeeds(a.seeds);
183	  const policyMod = require(path.resolve(a.policy));
184	
185	  let traceStream = null;
186	  let onStep = null;
187	  if (a.trace) {
188	    traceStream = fs.createWriteStream(a.trace, { flags: "w" });
189	    onStep = (rec) => traceStream.write(JSON.stringify(rec) + "\n");
190	  }
191	
192	  // Per-game logging: none | light (default) | full. Light is small + replayable.
193	  const logLevel = String(a.log || "light").toLowerCase();
194	  const captureLight = logLevel !== "none";
195	  const captureFull = logLevel === "full";
196	  const logDir = a["log-dir"] || "game_logs";
197	  const gameVersion = bundleVersion();
198	  // conflict-safe per-process token: ms-time (base36) + pid. Different invocations →
199	  // different tokens; multiple games within one invocation → distinct index.
200	  const runToken = Date.now().toString(36) + "-" + process.pid;
201	
202	  const env = new RogueEnv();
203	  const results = seeds.map((s) => runEpisode(env, policyMod, s, config, { onStep, captureLight, captureFull }));
204	  if (traceStream) traceStream.end();
205	
206	  const savedLogs = [];
207	  if (captureLight) {
208	    results.forEach((r, i) => {
209	      const p = writeGameLog(r, config, gameVersion, logLevel, logDir, runToken, i);
210	      if (p) savedLogs.push(p);
211	      delete r._gamelog; // keep it out of the printed JSON
212	    });
213	  }
214	  const agg = aggregate(results);
215	
216	  if (a.json) {
217	    process.stdout.write(JSON.stringify({ config: { ...config, speed_cap: a.speed_cap }, seeds, results, aggregate: agg, log_level: logLevel, game_logs: savedLogs }) + "\n");
218	  } else {
219	    console.log(`policy=${a.policy}  seeds=${seeds.length}  speed_cap=${a.speed_cap}  frame_skip=${config.frame_skip}  log=${logLevel}`);
220	    for (const r of results) {
221	      console.log(
222	        `  seed ${String(r.seed).padStart(4)}: progress ${String(Math.round((r.progress || 0) * 100) + "%").padStart(4)}  ` +
223	        `boss-HP-destroyed ${Math.round((r.boss_hp_destroyed || 0) * 100)}%  score ${String(r.score).padStart(8)}  survived ${Math.round(r.survived_ms / 1000)}s  ` +
224	        `kills ${r.kills}  lvl ${r.level}  wave ${r.wave}  ${r.boss_cleared ? "BOSS-CLEARED" : r.boss_reached ? "boss-reached" : ""}  (${r.done_reason})` +
225	        (r.policy_error ? `  ERROR:${r.policy_error}` : "")
226	      );
227	    }
228	    console.log("  --- aggregate ---");
229	    console.log(`  progress mean ${Math.round(agg.progress.mean * 100)}%  best ${Math.round(agg.progress.max * 100)}%   (1.0 = game cleared / 通关)`);
230	    console.log(`  score   mean ${agg.score.mean}  median ${agg.score.median}  min ${agg.score.min}  max ${agg.score.max}`);
231	    console.log(`  survived(ms) mean ${agg.survived_ms.mean}   kills mean ${agg.kills.mean}   level mean ${agg.level.mean}   wave mean ${agg.wave.mean}`);
232	    console.log(`  boss_reached ${agg.boss_reached_rate}  boss_cleared ${agg.boss_cleared_rate}  death ${agg.death_rate}  timeout ${agg.timeout_rate}`);
233	    if (savedLogs.length) console.log(`  saved ${savedLogs.length} replayable game log(s) -> ${logDir}/ (level=${logLevel}; expand with: node expand_trace.js <file>)`);
234	  }
235	}
236	
237	module.exports = { runEpisode, aggregate, TRAINING_SEEDS };
238

