"use strict";
// Exploratory probe: dump initial state and run a naive policy for N steps, logging notable things.
const { RogueEnv } = require("./env.bundle.js");

const seed = Number(process.argv[2] || 1);
const maxSteps = Number(process.argv[3] || 3000);

const env = new RogueEnv();
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

console.log("FIELD:", JSON.stringify(obs.field));
console.log("PLAYER:", JSON.stringify(obs.player, null, 1));
console.log("OBJECTS at t0:", JSON.stringify(obs.objects));

const seenEnemyTypes = new Map(); // enemy_type -> sample
const seenItemTypes = new Map();
const upgradeOptions = new Map(); // id -> sample
let events = [];
let lastWave = obs.wave;

for (let step = 0; step < maxSteps; step++) {
  // naive: stay near bottom center, dodge nothing
  let upgrade_choice = null;
  if (obs.pending_upgrade) {
    for (const o of obs.pending_upgrade.options) {
      if (!upgradeOptions.has(o.id)) upgradeOptions.set(o.id, o);
    }
    upgrade_choice = 0;
  }
  const r = env.step({ move: [0, 0], upgrade_choice });
  obs = r.obs;
  if (r.event) {
    events.push({ step, event: r.event });
    console.log("EVENT @", step, JSON.stringify(r.event));
  }
  if (obs.wave !== lastWave) {
    console.log("WAVE CHANGE @", step, lastWave, "->", obs.wave);
    lastWave = obs.wave;
  }
  for (const o of obs.objects) {
    if ((o.type === "enemy" || o.type === "enemy_elite") && !seenEnemyTypes.has(o.type + ":" + o.enemy_type)) {
      seenEnemyTypes.set(o.type + ":" + o.enemy_type, o);
    }
    if (o.type === "item" && !seenItemTypes.has(o.item_type)) seenItemTypes.set(o.item_type, o);
    if (o.type === "boss") {
      if (!seenEnemyTypes.has("boss:" + o.variant)) {
        seenEnemyTypes.set("boss:" + o.variant, o);
        console.log("BOSS SEEN @", step, JSON.stringify(o));
      }
    }
  }
  if (r.done) {
    console.log("DONE @", step, JSON.stringify(r.reward_info));
    break;
  }
}

console.log("\nENEMY TYPES SEEN:");
for (const [k, v] of seenEnemyTypes) console.log(" ", k, JSON.stringify(v));
console.log("\nITEM TYPES SEEN:");
for (const [k, v] of seenItemTypes) console.log(" ", k, JSON.stringify(v));
console.log("\nUPGRADE OPTIONS SEEN:");
for (const [k, v] of upgradeOptions) console.log(" ", k, JSON.stringify(v));
console.log("\nFINAL reward_info:", JSON.stringify(obs.reward_info));
console.log("FINAL player:", JSON.stringify(obs.player));

