"use strict";
// Probe 2: inspect player bullets, enemy motion, contact damage.
const { RogueEnv } = require("./env.bundle.js");

const env = new RogueEnv();
let { obs } = env.reset(1, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

// Phase A: watch first 240 ticks; print player bullets and enemies every 30 ticks.
for (let step = 0; step < 240; step++) {
  const r = env.step({ move: [0, 0], upgrade_choice: null });
  obs = r.obs;
  if (step % 30 === 0) {
    const bullets = obs.objects.filter(o => o.type === "player_bullet");
    const enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite");
    console.log(`t=${obs.frame} bullets=${bullets.length} enemies=${enemies.length}`);
    if (bullets.length) console.log("  bullet sample:", JSON.stringify(bullets[0]));
    for (const e of enemies.slice(0, 4)) console.log("  enemy:", JSON.stringify({ id: e.id, et: e.enemy_type, pos: e.pos.map(v=>Math.round(v)), vel: e.vel, hp: e.hp }));
  }
}

// Phase B: ram into the nearest enemy to test contact damage.
console.log("\n--- contact damage test ---");
let lastHp = obs.player.hp;
for (let step = 0; step < 600; step++) {
  const enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite");
  let move = [0, 0];
  if (enemies.length) {
    // chase the nearest
    let best = null, bd = 1e9;
    for (const e of enemies) {
      const d = Math.hypot(e.pos[0] - obs.player.pos[0], e.pos[1] - obs.player.pos[1]);
      if (d < bd) { bd = d; best = e; }
    }
    move = [best.pos[0] - obs.player.pos[0], best.pos[1] - obs.player.pos[1]];
  }
  const r = env.step({ move, upgrade_choice: obs.pending_upgrade ? 0 : null });
  obs = r.obs;
  if (obs.player.hp !== lastHp) {
    console.log(`t=${obs.frame} hp ${lastHp} -> ${obs.player.hp} (invinc ${obs.player.invincible_ms}ms)`);
    lastHp = obs.player.hp;
  }
  if (r.event) console.log("EVENT:", JSON.stringify(r.event));
  if (r.done) { console.log("DONE", JSON.stringify(r.reward_info)); break; }
}
console.log("player:", JSON.stringify(obs.player));
console.log("reward:", JSON.stringify({ kills: obs.reward_info.kills, hp: obs.reward_info.hp, progress: obs.reward_info.progress }));

