"use strict";
// Dev runner: run ./policy.js with verbose event logging for study.
// Usage: node dev_run.js [seed] [max_steps] [--quiet]
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 1);
const maxSteps = Number(process.argv[3] || 90000);
const quiet = process.argv.includes("--quiet");

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: maxSteps });

let lastHp = obs.player.hp, lastWave = obs.wave, lastLevel = obs.player.level;
const upgradesTaken = [];
const optionsSeen = new Map();
let hpLossEvents = 0;
let bossSeen = new Set();

for (let step = 0; step < maxSteps + 5; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  let chosen = null;
  if (obs.pending_upgrade) {
    const opts = obs.pending_upgrade.options;
    for (const o of opts) optionsSeen.set(o.id, o);
    chosen = opts.find(o => o.index === out.action.upgrade_choice);
    if (!quiet) console.log(`[lvlup @${step}] options: ${opts.map(o => `${o.index}:${o.id}(${o.rarity})`).join(" | ")} -> chose ${chosen ? chosen.id : out.action.upgrade_choice}`);
    if (chosen) upgradesTaken.push(chosen.id);
  }
  const r = env.step(out.action);
  obs = r.obs;
  if (obs.player.hp < lastHp) {
    hpLossEvents++;
    if (!quiet) console.log(`[dmg @${step}] hp ${lastHp} -> ${obs.player.hp} pos=${obs.player.pos.map(v=>Math.round(v))} wave=${obs.wave}`);
  }
  lastHp = obs.player.hp;
  if (obs.wave !== lastWave) {
    console.log(`[wave @${step}] ${lastWave} -> ${obs.wave}  t=${Math.round(obs.time_ms/1000)}s level=${obs.player.level} kills=${obs.reward_info.kills} progress=${obs.reward_info.progress}`);
    lastWave = obs.wave;
  }
  if (r.event && r.event.kind === "boss_phase") {
    const e = r.event;
    const key = `${e.variant}:${e.hp_layers_left}:${e.first_sight}`;
    if (!bossSeen.has(key)) {
      bossSeen.add(key);
      console.log(`[boss @${step}] ${JSON.stringify(e)} t=${Math.round(obs.time_ms/1000)}s progress=${obs.reward_info.progress}`);
    }
  }
  if (r.event && r.event.kind === "game_over") {
    console.log(`[game_over @${step}] ${JSON.stringify(r.event)}`);
  }
  if (step % 6000 === 0 && step > 0) {
    const ri = obs.reward_info;
    console.log(`[t @${step}] t=${Math.round(obs.time_ms/1000)}s wave=${ri.wave} lvl=${ri.level} kills=${ri.kills} hp=${ri.hp} progress=${ri.progress} boss_active=${ri.boss_active}` +
      ` shoot=${obs.player.shoot_interval_ms}ms side=${obs.player.side_bullets} pierce=${obs.player.pierce} sat=${obs.player.satellites}`);
  }
  if (r.done) break;
}

const ri = obs.reward_info;
console.log("\n=== RESULT ===");
console.log(JSON.stringify({
  seed, steps: ri.steps, done: ri.done_reason, progress: ri.progress, wave: ri.wave,
  level: ri.level, kills: ri.kills, hp: ri.hp, score: ri.score,
  boss_reached: ri.boss_reached, boss_cleared: ri.boss_cleared,
  boss_hp_destroyed: ri.boss_hp_destroyed, survived_s: Math.round(ri.survived_ms/1000),
  hpLossEvents,
}));
console.log("upgrades taken:", upgradesTaken.join(", "));
console.log("\nall options ever seen:");
for (const [, o] of optionsSeen) console.log(` ${o.id} (${o.rarity}): ${o.name} — ${o.desc}`);

