"use strict";
/**
 * Roguelike Skies policy v2.
 * - Farm waves hard: align under enemies to kill fast, scoop exp, level up.
 * - Upgrade priority: DPS multipliers > exp early > utility > defense.
 * - Dodge enemy bullets/bodies with predictive candidate-move search.
 */

function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

// ---------- upgrades ----------
const UPGRADE_SCORE = {
  ms_split_s: 100,   // 3-way shot
  fr_basic: 80,      // +32% fire rate
  crit_aim: 74,      // +20% crit
  mix_fire: 72,      // +8% dmg +15% rate
  dmg_s: 70,         // +12% dmg
  sat_orbit: 65,     // +2 homing satellites
  pc_pierce: 62,     // pierce
  bs_size_s: 55,     // bullet size +100%
  elite_hunter: 50,  // +40% vs elites
  exp_basic: 58,     // +100% exp (great early; handled dynamically)
  mag_basic: 46,     // +175% pickup radius (early)
  kill_pulse: 35,
  shield_basic: 30,
  shield_extra: 32,
  regen_basic: 25,
  heal_overflow: 14,
  kill_blood: 15,
  turncoat_shield: 18,
  heal_quick: 12,
  coin_small: 2,
  mix_econ: 4,
};
const RARITY_SCORE = { green: 0, blue: 2, purple: 4, orange: 6 };

function scoreUpgrade(opt, obs) {
  const id = String(opt.id || "");
  let s = UPGRADE_SCORE.hasOwnProperty(id) ? UPGRADE_SCORE[id] : 40 + (RARITY_SCORE[opt.rarity] || 0) * 6;
  s += (RARITY_SCORE[opt.rarity] || 0);
  const lvl = obs.player.level || 1;
  // exp & magnet are most valuable early
  if (id === "exp_basic" && lvl <= 8) s += 30;
  if (id === "mag_basic" && lvl <= 8) s += 20;
  // defense matters when hurt
  const hpFrac = obs.player.hp / Math.max(1, obs.player.max_hp);
  if (hpFrac < 0.45) {
    if (id === "heal_quick") s += 70;
    if (id === "shield_basic" || id === "shield_extra") s += 40;
    if (id === "regen_basic") s += 25;
  }
  return s;
}

function chooseUpgrade(obs) {
  const pu = obs.pending_upgrade;
  if (!pu || !pu.options || !pu.options.length) return null;
  let best = pu.options[0].index, bestScore = -Infinity;
  for (const o of pu.options) {
    const s = scoreUpgrade(o, obs);
    if (s > bestScore) { bestScore = s; best = o.index; }
  }
  return best;
}

// ---------- hazards ----------
function buildHazards(obs) {
  const hz = [];
  for (const o of obs.objects) {
    if (o.type === "enemy_bullet") {
      hz.push({ x: o.pos[0], y: o.pos[1], vx: o.vel[0], vy: o.vel[1], r: Math.max(o.size[0], o.size[1]) / 2 + 3, body: false });
    } else if (o.type === "enemy" || o.type === "enemy_elite") {
      hz.push({ x: o.pos[0], y: o.pos[1], vx: o.vel[0], vy: o.vel[1], r: Math.max(o.size[0], o.size[1]) / 2 + 5, body: true });
    } else if (o.type === "boss") {
      hz.push({ x: o.pos[0], y: o.pos[1], vx: o.vel[0], vy: o.vel[1], r: Math.max(o.size[0], o.size[1]) / 2 + 6, body: true });
    }
  }
  return hz;
}

function dangerAt(x, y, hazards, horizon, playerR) {
  let d = 0;
  for (let i = 0; i < hazards.length; i++) {
    const h = hazards[i];
    // quick reject: too far to matter within horizon
    const dx0 = h.x - x, dy0 = h.y - y;
    const dist0 = Math.hypot(dx0, dy0);
    const maxSpeed = Math.hypot(h.vx, h.vy) * horizon + h.r + playerR + 30;
    if (dist0 > maxSpeed) continue;
    for (let t = 0; t <= horizon; t++) {
      const hx = h.x + h.vx * t;
      const hy = h.y + h.vy * t;
      const dist = Math.hypot(hx - x, hy - y);
      const rr = h.r + playerR;
      if (dist < rr) {
        d += (h.body ? 5000 : 2500) / (1 + t * 0.7);
      } else if (dist < rr + 26) {
        d += ((h.body ? 700 : 350) / (1 + t * 0.7)) * (1 - (dist - rr) / 26);
      }
    }
  }
  return d;
}

// ---------- targeting ----------
function pickTargetX(obs) {
  const px = obs.player.pos[0], py = obs.player.pos[1];
  let boss = null;
  const enemies = [];
  for (const o of obs.objects) {
    if (o.type === "boss" && !o.in_cutscene) boss = o;
    else if (o.type === "enemy" || o.type === "enemy_elite") {
      if (o.pos[1] < py - 20) enemies.push(o); // only ones above us are hittable
    }
  }
  if (boss) {
    // lead the boss slightly by its velocity (bullet flight time)
    const flight = Math.max(0, (py - boss.pos[1]) / 8.5);
    return { x: boss.pos[0] + boss.vel[0] * Math.min(flight, 30) * 0.5, important: true };
  }
  if (!enemies.length) return null;
  // pick enemy: prefer low (large y), close in x, low hp (quick kills)
  let best = null, bestScore = -Infinity;
  for (const e of enemies) {
    const alignCost = Math.abs(e.pos[0] - px);
    const s = e.pos[1] * 1.0 - alignCost * 0.8 - (e.hp / 1000) * 8;
    if (s > bestScore) { bestScore = s; best = e; }
  }
  const flight = Math.max(0, (py - best.pos[1]) / 8.5);
  return { x: best.pos[0] + best.vel[0] * Math.min(flight, 40) * 0.6, important: false };
}

const ITEM_VALUE = {
  exp_small: 1, exp_medium: 3, exp_large: 8, exp_huge: 20,
  heart: 6, bomb: 8, magnet: 8, coin: 0.5, levelup: 30, invincible: 8,
};

function pickItem(obs) {
  const px = obs.player.pos[0], py = obs.player.pos[1];
  let best = null, bestScore = -Infinity;
  for (const o of obs.objects) {
    if (o.type !== "item") continue;
    const v = ITEM_VALUE.hasOwnProperty(o.item_type) ? ITEM_VALUE[o.item_type] : (o.exp_value || 1);
    const d = Math.hypot(o.pos[0] - px, o.pos[1] - py);
    // items fall; ones above us will come to us. Prefer close + valuable.
    const s = v * 28 - d;
    if (s > bestScore) { bestScore = s; best = o; }
  }
  return best;
}

module.exports = {
  init() { return {}; },

  policy(obs, mem) {
    try {
      const upgrade_choice = chooseUpgrade(obs);
      const p = obs.player;
      const px = p.pos[0], py = p.pos[1];
      const W = (obs.field && obs.field.w) || 360;
      const H = (obs.field && obs.field.h) || 640;
      const playerR = Math.max(p.size[0], p.size[1]) / 2;
      const cap = 40;

      const hazards = buildHazards(obs);
      const target = pickTargetX(obs);
      const item = pickItem(obs);

      // Desired position
      const baseY = H - 120; // comfortable shooting band
      let desX = px, desY = baseY;
      if (target) desX = target.x;
      if (item) {
        const di = Math.hypot(item.pos[0] - px, item.pos[1] - py);
        const v = ITEM_VALUE.hasOwnProperty(item.item_type) ? ITEM_VALUE[item.item_type] : 1;
        // chase valuable/close items; fold pickup into the goal position
        if (!target || !target.important || v >= 6 || di < 140) {
          // intercept where the item will be soon
          const ix = item.pos[0] + item.vel[0] * 4;
          const iy = item.pos[1] + item.vel[1] * 4;
          if (v >= 6 || di < 200) { desX = ix; desY = clamp(iy, 90, H - 50); }
        }
      }
      desX = clamp(desX, 25, W - 25);
      desY = clamp(desY, 80, H - 35);

      // Candidate moves
      const candidates = [[0, 0], [clamp(desX - px, -cap, cap), clamp(desY - py, -cap, cap)]];
      const dirs = 16;
      for (let i = 0; i < dirs; i++) {
        const a = (2 * Math.PI * i) / dirs;
        candidates.push([Math.cos(a) * 12, Math.sin(a) * 12]);
        candidates.push([Math.cos(a) * 28, Math.sin(a) * 28]);
        candidates.push([Math.cos(a) * 40, Math.sin(a) * 40]);
      }

      let bestMove = [0, 0], bestScore = -Infinity;
      for (const mv of candidates) {
        let nx = clamp(px + mv[0], playerR, W - playerR);
        let ny = clamp(py + mv[1], playerR, H - playerR);
        let s = -dangerAt(nx, ny, hazards, 9, playerR);
        s -= Math.abs(nx - desX) * 1.2;
        s -= Math.abs(ny - desY) * 0.6;
        if (nx < 24 || nx > W - 24) s -= 25;
        if (ny > H - 30 || ny < 60) s -= 25;
        if (s > bestScore) { bestScore = s; bestMove = mv; }
      }

