"use strict";
/**
 * Roguelike Skies policy.
 * Core loop: pick a target enemy, align x under it to let autofire hit, dodge
 * enemy bullets and enemy bodies, scoop up item drops, choose upgrades.
 */

const FIELD_W = 360, FIELD_H = 640;

// ---------- helpers ----------
function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

// Rate upgrade options; higher = better. Tuned as we learn the upgrade pool.
const RARITY_SCORE = { green: 0, blue: 1, purple: 2, orange: 3 };
function scoreUpgrade(opt) {
  let s = (RARITY_SCORE[opt.rarity] || 0) * 10;
  const id = String(opt.id || "").toLowerCase();
  const name = String(opt.name || "").toLowerCase();
  const txt = id + " " + name + " " + String(opt.desc || "").toLowerCase();
  // crude keyword preferences (refine after seeing the real pool)
  if (/damage|dmg|attack|atk/.test(txt)) s += 6;
  if (/fire|rate|interval|speed.*shoot|shoot.*speed|rapid/.test(txt)) s += 6;
  if (/side|multi|spread|stream/.test(txt)) s += 5;
  if (/pierce/.test(txt)) s += 5;
  if (/satellite|orbit/.test(txt)) s += 4;
  if (/magnet|pickup/.test(txt)) s += 3;
  if (/hp|heal|shield|life/.test(txt)) s += 2;
  return s;
}

function chooseUpgrade(obs) {
  const opts = obs.pending_upgrade && obs.pending_upgrade.options;
  if (!opts || !opts.length) return null;
  let best = 0, bestScore = -Infinity;
  for (const o of opts) {
    const s = scoreUpgrade(o);
    if (s > bestScore) { bestScore = s; best = o.index; }
  }
  return best;
}

// ---------- movement ----------
// Treat enemy bullets + enemy bodies as moving hazards; do a 1-step lookahead over
// candidate moves, scoring safety + goal proximity.

function hazardsFrom(obs) {
  const hz = [];
  for (const o of obs.objects) {
    if (o.type === "enemy_bullet") {
      hz.push({ pos: o.pos, vel: o.vel, r: Math.max(o.size[0], o.size[1]) / 2 + 4, kind: "bullet" });
    } else if (o.type === "enemy" || o.type === "enemy_elite") {
      hz.push({ pos: o.pos, vel: o.vel, r: Math.max(o.size[0], o.size[1]) / 2 + 6, kind: "body" });
    } else if (o.type === "boss" && !o.in_cutscene) {
      hz.push({ pos: o.pos, vel: o.vel, r: Math.max(o.size[0], o.size[1]) / 2 + 8, kind: "body" });
    }
  }
  return hz;
}

// Danger of being at (x,y) over the next H ticks given hazards moving linearly.
function dangerAt(x, y, hazards, H, playerR) {
  let d = 0;
  for (const h of hazards) {
    for (let t = 0; t <= H; t++) {
      const hx = h.pos[0] + h.vel[0] * t;
      const hy = h.pos[1] + h.vel[1] * t;
      const dist = Math.hypot(hx - x, hy - y);
      const rr = h.r + playerR;
      if (dist < rr) {
        d += (h.kind === "body" ? 4000 : 2000) / (1 + t);
      } else if (dist < rr + 25) {
        d += ((h.kind === "body" ? 600 : 300) / (1 + t)) * (1 - (dist - rr) / 25);
      }
    }
  }
  return d;
}

function pickTarget(obs) {
  // Prefer boss; otherwise the enemy that is lowest (most threatening / easiest to hit soon).
  let boss = null;
  const enemies = [];
  for (const o of obs.objects) {
    if (o.type === "boss" && !o.in_cutscene) boss = o;
    else if (o.type === "enemy" || o.type === "enemy_elite") enemies.push(o);
  }
  if (boss) return boss;
  if (!enemies.length) return null;
  let best = null, bestScore = -Infinity;
  for (const e of enemies) {
    // prioritize lower (higher y), closer in x
    const s = e.pos[1] - Math.abs(e.pos[0] - obs.player.pos[0]) * 0.3;
    if (s > bestScore) { bestScore = s; best = e; }
  }
  return best;
}

function pickItem(obs) {
  let best = null, bestScore = -Infinity;
  for (const o of obs.objects) {
    if (o.type !== "item") continue;
    const d = Math.hypot(o.pos[0] - obs.player.pos[0], o.pos[1] - obs.player.pos[1]);
    const value = (o.exp_value || 1) + (o.item_type === "heart" ? 5 : 0) +
      (o.item_type === "magnet" ? 3 : 0) + (o.item_type === "levelup" ? 10 : 0) +
      (o.item_type === "invincible" ? 4 : 0) + (o.item_type === "bomb" ? 3 : 0);
    const s = value * 30 - d;
    if (s > bestScore) { bestScore = s; best = o; }
  }
  return best;
}

module.exports = {
  init() { return {}; },

  policy(obs, mem) {
    try {
      const upgrade_choice = chooseUpgrade(obs);
      const p = obs.player;
      const [px, py] = p.pos;
      const cap = 40; // speed cap assumed; magnitude-clamped anyway
      const playerR = Math.max(p.size[0], p.size[1]) / 2;
      const W = (obs.field && obs.field.w) || FIELD_W;
      const H = (obs.field && obs.field.h) || FIELD_H;

      const hazards = hazardsFrom(obs);
      const target = pickTarget(obs);
      const item = pickItem(obs);

      // Desired position: under target x, at a comfortable y near the bottom,
      // adjusted toward valuable items.
      let desX = px, desY = clamp(py, H * 0.7, H - 60);
      if (target) desX = target.pos[0];
      if (item) {
        const di = Math.hypot(item.pos[0] - px, item.pos[1] - py);
        // chase items that are close or valuable; weight item position into goal
        if (di < 220) { desX = item.pos[0]; desY = clamp(item.pos[1], H * 0.35, H - 40); }
      }
      desY = clamp(desY, 80, H - 40);

      // Candidate moves: directions x speeds, plus hold.
      const candidates = [[0, 0]];
      const dirs = 16;
      for (let i = 0; i < dirs; i++) {
        const a = (2 * Math.PI * i) / dirs;
        for (const sp of [8, 20, 40]) {
          candidates.push([Math.cos(a) * sp, Math.sin(a) * sp]);
        }
      }
      // Also a direct "go to desired" move
      candidates.push([clamp(desX - px, -cap, cap), clamp(desY - py, -cap, cap)]);

      let bestMove = [0, 0], bestScore = -Infinity;
      for (const mv of candidates) {
        let nx = px + mv[0], ny = py + mv[1];
        nx = clamp(nx, playerR, W - playerR);
        ny = clamp(ny, playerR, H - playerR);
        let s = 0;
        s -= dangerAt(nx, ny, hazards, 8, playerR);
        // goal attraction
        s -= Math.abs(nx - desX) * 1.0;
        s -= Math.abs(ny - desY) * 0.5;
        // small preference for staying away from walls
        if (nx < 30 || nx > W - 30) s -= 20;
        if (ny > H - 35) s -= 30;
        if (s > bestScore) { bestScore = s; bestMove = mv; }
      }

      return { action: { move: bestMove, upgrade_choice }, mem };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem };
    }
  },
};

