"use strict";
// Replay ./policy.js on a seed and dump detailed state in a step window.
// Usage: node inspect.js <seed> <from> <to> [fields]
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 1);
const from = Number(process.argv[3] || 0);
const to = Number(process.argv[4] || from + 50);

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

for (let step = 0; step <= to; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  const r = env.step(out.action);
  obs = r.obs;
  if (step >= from) {
    const p = obs.player;
    const boss = obs.objects.find(o => o.type === "boss");
    const bullets = obs.objects.filter(o => o.type === "enemy_bullet");
    const enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite");
    console.log(`s=${step} mv=[${out.action.move.map(v=>Math.round(v))}] p=[${p.pos.map(v=>Math.round(v))}] hp=${p.hp}+${p.shield_hp} ` +
      `boss=${boss ? `${boss.variant}@[${boss.pos.map(v=>Math.round(v))}] v=[${boss.vel.map(v=>Math.round(v*10)/10)}] sz=[${boss.size.map(v=>Math.round(v))}] hp=${(boss.hp/1e6).toFixed(2)}M cut=${boss.in_cutscene}` : "-"} ` +
      `eb=${bullets.length} en=${enemies.length}`);
    // nearest bullets
    const near = bullets.map(b => ({ b, d: Math.hypot(b.pos[0]-p.pos[0], b.pos[1]-p.pos[1]) }))
      .sort((a,b)=>a.d-b.d).slice(0,5);
    for (const { b, d } of near) {
      if (d < 120) console.log(`   eb id=${b.id} pos=[${b.pos.map(v=>Math.round(v))}] vel=[${b.vel.map(v=>Math.round(v*10)/10)}] sz=[${b.size.map(v=>Math.round(v))}] dmg=${b.dmg} d=${Math.round(d)}`);
    }
  }
  if (r.done) { console.log("DONE", JSON.stringify(r.reward_info)); break; }
}

