"use strict";
// Observe boss behavior with current policy: boss kinematics, bullet spawn patterns, add spawns.
// Usage: node probe_boss.js <seed> <fromStep> <toStep>
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 1);
const from = Number(process.argv[3] || 5300);
const to = Number(process.argv[4] || 9000);

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

let bossMinX = 1e9, bossMaxX = -1e9, bossMinY = 1e9, bossMaxY = -1e9;
let maxBossSpeed = 0;
const bulletSpeeds = new Map(); // rounded speed -> count
const bulletDirs = { up: 0, down: 0, side: 0 };
let aimedCount = 0, totalSpawned = 0;
const addTypes = new Map();
let prevById = new Map();

for (let step = 0; step <= to; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  const r = env.step(out.action);
  obs = r.obs;
  if (step >= from) {
    const boss = obs.objects.find(o => o.type === "boss");
    if (boss && !boss.in_cutscene) {
      bossMinX = Math.min(bossMinX, boss.pos[0]); bossMaxX = Math.max(bossMaxX, boss.pos[0]);
      bossMinY = Math.min(bossMinY, boss.pos[1]); bossMaxY = Math.max(bossMaxY, boss.pos[1]);
      maxBossSpeed = Math.max(maxBossSpeed, Math.hypot(boss.vel[0], boss.vel[1]));
    }
    const byId = new Map(obs.objects.map(o => [o.id, o]));
    for (const id of obs.spawned || []) {
      const o = byId.get(id);
      if (!o) continue;
      if (o.type === "enemy_bullet") {
        totalSpawned++;
        const sp = Math.round(Math.hypot(o.vel[0], o.vel[1]) * 2) / 2;
        bulletSpeeds.set(sp, (bulletSpeeds.get(sp) || 0) + 1);
        if (o.vel[1] > 0.5) bulletDirs.down++;
        else if (o.vel[1] < -0.5) bulletDirs.up++;
        else bulletDirs.side++;
        // aimed at player? angle between vel and (player - pos)
        const dx = obs.player.pos[0] - o.pos[0], dy = obs.player.pos[1] - o.pos[1];
        const dn = Math.hypot(dx, dy), vn = Math.hypot(o.vel[0], o.vel[1]);
        if (dn > 1 && vn > 0.01) {
          const cos = (dx * o.vel[0] + dy * o.vel[1]) / (dn * vn);
          if (cos > 0.985) aimedCount++;
        }
      } else if (o.type === "enemy" || o.type === "enemy_elite") {
        const k = o.type + ":" + o.enemy_type + ":hp" + o.max_hp;
        addTypes.set(k, (addTypes.get(k) || 0) + 1);
      }
    }
  }
  if (r.done) { console.log("DONE @", step, JSON.stringify({ reason: r.reward_info.done_reason, hp: r.reward_info.hp })); break; }
}

console.log("boss x range:", Math.round(bossMinX), "-", Math.round(bossMaxX), " y range:", Math.round(bossMinY), "-", Math.round(bossMaxY), " max speed:", maxBossSpeed.toFixed(2));
console.log("enemy bullets spawned:", totalSpawned, " aimed-at-player frac:", (aimedCount / Math.max(1, totalSpawned)).toFixed(2));
console.log("bullet dirs:", JSON.stringify(bulletDirs));
console.log("bullet speeds:", [...bulletSpeeds.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8).map(([s,c])=>`${s}px/t x${c}`).join(", "));
console.log("adds spawned during window:", [...addTypes.entries()].map(([k,c])=>`${k} x${c}`).join(", "));

