"use strict";
/**
 * Roguelike Skies policy v5.
 * - Trajectory-based dodging with hazard position cache.
 * - During boss: farm adds/items while DPS is low, focus boss when strong.
 * - Upgrades: DPS multipliers + exp engine early; lifesteal/shields valued for long fights.
 */

function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

// ---------- upgrades ----------
const UPGRADE_SCORE = {
  ms_split_l: 120, ms_split_m: 110, ms_split_s: 100,
  fr_cool: 85, fr_basic: 80,
  mix_perfect: 95, mix_vulcan: 88, mix_terminal: 86, mix_fire: 72,
  dmg_l: 84, dmg_m: 78, dmg_s: 70,
  crit_lethal: 76, crit_aim: 74,
  boss_hunter: 90,
  sat_orbit: 65,
  pc_pierce: 66,
  bs_size_s: 56, bs_size_m: 58,
  elite_hunter: 52,
  exp_quantum: 115, exp_smart: 75, exp_basic: 58,
  mag_well: 48, mag_basic: 44,
  drop_basic: 38,
  reroll_premium: 55,
  kill_pulse: 30, kill_pulse_3: 50,
  timeflow_shield: 47,
  shield_extra: 50, shield_basic: 50,
  regen_basic: 35,
  heal_overflow: 16, kill_blood: 45, kill_butcher: 70,
  thorn_static: 8, thorn_blaze: 10,
  turncoat_shield: 18,
  heal_quick: 14,
  coin_small: 2, mix_econ: 4,
};
const RARITY_SCORE = { green: 0, blue: 2, purple: 4, orange: 6 };

function scoreUpgrade(opt, obs) {
  const id = String(opt.id || "");
  let s = UPGRADE_SCORE.hasOwnProperty(id) ? UPGRADE_SCORE[id] : 45 + (RARITY_SCORE[opt.rarity] || 0) * 8;
  s += (RARITY_SCORE[opt.rarity] || 0);
  const lvl = obs.player.level || 1;
  if (id === "exp_basic" && lvl <= 8) s += 30;
  if (id === "exp_smart" && lvl <= 14) s += 25;
  if (id === "mag_basic" && lvl <= 8) s += 22;
  if (id === "mag_well" && lvl <= 14) s += 20;
  // ensure a shield before/during boss pressure
  if ((id === "shield_basic" || id === "shield_extra") && obs.player.shield_max <= 0) s += 18;
  const hpFrac = obs.player.hp / Math.max(1, obs.player.max_hp);
  if (hpFrac < 0.45) {
    if (id === "heal_quick") s += 80;
    if (id === "shield_basic" || id === "shield_extra") s += 45;
    if (id === "regen_basic") s += 25;
    if (id === "kill_blood" || id === "kill_butcher") s += 20;
  }
  return s;
}

function chooseUpgrade(obs) {
  const pu = obs.pending_upgrade;
  if (!pu || !pu.options || !pu.options.length) return null;
  let best = pu.options[0].index, bestScore = -Infinity;
  for (const o of pu.options) {
    const s = scoreUpgrade(o, obs);
    if (s > bestScore) { bestScore = s; best = o.index; }
  }
  return best;
}

// ---------- movement ----------
const HORIZON = 14;

function buildHazards(obs, px, py) {
  const hz = [];
  const R = 340;
  for (const o of obs.objects) {
    let r, body, boss = false;
    if (o.type === "enemy_bullet") { r = Math.max(o.size[0], o.size[1]) / 2 + 4; body = false; }
    else if (o.type === "enemy" || o.type === "enemy_elite") { r = Math.max(o.size[0], o.size[1]) / 2 + 7; body = true; }
    else if (o.type === "boss") {
      const sp = Math.hypot(o.vel[0], o.vel[1]);
      r = Math.max(o.size[0], o.size[1]) / 2 + 22 + Math.min(sp * 2.5, 30);
      body = true; boss = true;
    }
    else continue;
    const dx = o.pos[0] - px, dy = o.pos[1] - py;
    if (Math.abs(dx) > R || Math.abs(dy) > R) continue;
    const xs = new Float64Array(HORIZON + 1);
    const ys = new Float64Array(HORIZON + 1);
    for (let t = 0; t <= HORIZON; t++) {
      xs[t] = o.pos[0] + o.vel[0] * t;
      ys[t] = o.pos[1] + o.vel[1] * t;
    }
    hz.push({ xs, ys, r, body, boss });
  }
  return hz;
}

// Swept (continuous) risk for the player moving from (x,y) with velocity (pvx,pvy)
// during tick t -> t+1, against each hazard moving linearly. Catches tunneling.
function riskSwept(x, y, pvx, pvy, t, hazards, playerR) {
  let d = 0;
  const decay = 1 / (1 + t * 0.45);
  for (let i = 0; i < hazards.length; i++) {
    const h = hazards[i];
    // relative position at start of tick, relative velocity over the tick
    const rx = h.xs[t] - x, ry = h.ys[t] - y;
    const rvx = (h.xs[t + 1] - h.xs[t]) - pvx;
    const rvy = (h.ys[t + 1] - h.ys[t]) - pvy;
    const rr = h.r + playerR;
    const near = rr + 34;
    // quick reject using conservative bounds
    const reach = Math.abs(rvx) + Math.abs(rvy);
    if (Math.abs(rx) > near + reach || Math.abs(ry) > near + reach) continue;
    // min distance over s in [0,1] of |r + rv*s|
    const vv = rvx * rvx + rvy * rvy;
    let s = vv > 1e-9 ? -(rx * rvx + ry * rvy) / vv : 0;
    if (s < 0) s = 0; else if (s > 1) s = 1;
    const cx = rx + rvx * s, cy = ry + rvy * s;
    const dist = Math.sqrt(cx * cx + cy * cy);
    if (dist < rr) {
      d += (h.body ? 6500 : 2600) * decay;
    } else if (dist < near) {
      const frac = 1 - (dist - rr) / 34;
      d += (h.body ? 900 : 420) * decay * frac * frac;
    }
  }
  return d;
}

// ---------- targeting ----------
function getBoss(obs) {
  for (const o of obs.objects) if (o.type === "boss") return o;
  return null;
}

function pickEnemyTarget(obs) {
  const px = obs.player.pos[0], py = obs.player.pos[1];
  let best = null, bestScore = -Infinity;
  for (const o of obs.objects) {
    if (o.type !== "enemy" && o.type !== "enemy_elite") continue;
    if (o.pos[1] >= py - 15) continue;
    const alignCost = Math.abs(o.pos[0] - px);
    const s = o.pos[1] - alignCost * 0.8 - (o.hp / 1000) * 6 + (o.type === "enemy_elite" ? 40 : 0);
    if (s > bestScore) { bestScore = s; best = o; }
  }
  if (!best) return null;
  const flight = Math.max(0, (py - best.pos[1]) / 8.5);
  return { x: best.pos[0] + best.vel[0] * Math.min(flight, 40) * 0.6 };
}

const ITEM_VALUE = {
  exp_small: 1, exp_medium: 3, exp_large: 8, exp_huge: 20,
  heart: 6, bomb: 8, magnet: 9, coin: 0.5, levelup: 40, invincible: 8,
};

function pickItem(obs) {
  const px = obs.player.pos[0], py = obs.player.pos[1];
  let best = null, bestScore = -Infinity, bestV = 0;
  for (const o of obs.objects) {
    if (o.type !== "item") continue;
    let v = ITEM_VALUE.hasOwnProperty(o.item_type) ? ITEM_VALUE[o.item_type] : (o.exp_value || 1);
    if (o.item_type === "heart" && obs.player.hp < obs.player.max_hp * 0.6) v = 18;
    const d = Math.hypot(o.pos[0] - px, o.pos[1] - py);
    const s = v * 28 - d;
    if (s > bestScore) { bestScore = s; best = o; bestV = v; }
  }
  return best ? { item: best, value: bestV } : null;
}

module.exports = {
  init() {
    return { dmgSeen: 1000, streamSeen: 1, lastShotFrame: 0 };
  },

  policy(obs, mem) {
    try {
      const m = mem && typeof mem === "object" ? mem : { dmgSeen: 1000, streamSeen: 1 };
      const upgrade_choice = chooseUpgrade(obs);
      const p = obs.player;
      const px = p.pos[0], py = p.pos[1];
      const W = (obs.field && obs.field.w) || 360;
      const H = (obs.field && obs.field.h) || 640;
      const playerR = Math.max(p.size[0], p.size[1]) / 2;
      const cap = 40;

      // --- DPS proxy from observed player bullets ---
      const spawnedSet = new Set(obs.spawned || []);
      let streams = 0;
      for (const o of obs.objects) {
        if (o.type === "player_bullet") {
          if (o.dmg > m.dmgSeen) m.dmgSeen = o.dmg;
          if (spawnedSet.has(o.id)) streams++;
        }
      }
      if (streams > m.streamSeen) m.streamSeen = streams;
      const shotsPerSec = 1000 / Math.max(60, p.shoot_interval_ms || 420);
      // streams that can hit one target ~ min(streamSeen, 3) without bs_size; rough proxy
      const dpsProxy = shotsPerSec * m.dmgSeen * Math.min(m.streamSeen, 3) * (p.pierce ? 1.5 : 1);

      const hazards = buildHazards(obs, px, py);
      const boss = getBoss(obs);
      const itemPick = pickItem(obs);

      // ----- desired position -----
      let desX, desY;
      const bossLive = boss && !boss.in_cutscene;
      const focusBoss = bossLive && (dpsProxy > 22000 || (boss.hp / boss.max_hp) < 0.18);
      if (boss && boss.in_cutscene) {
        desX = W / 2; desY = H - 90;
      } else if (bossLive && focusBoss) {
        const bw = boss.size[0];
        const overlapDist = clamp(bw * 3.2, 200, 330);
        desX = boss.pos[0] + boss.vel[0] * 6;
        desY = clamp(boss.pos[1] + boss.size[1] / 2 + overlapDist, 380, H - 70);
      } else {
        const t = pickEnemyTarget(obs);
        if (t) { desX = t.x; desY = H - 115; }
        else if (bossLive) {
          const bw = boss.size[0];
          desX = boss.pos[0] + boss.vel[0] * 6;
          desY = clamp(boss.pos[1] + boss.size[1] / 2 + clamp(bw * 3.2, 200, 330), 380, H - 70);
        } else { desX = W / 2; desY = H - 115; }
      }
      // items adjust the goal; in farm mode chase aggressively
      if (itemPick && !(boss && boss.in_cutscene)) {
        const it = itemPick.item, v = itemPick.value;
        const di = Math.hypot(it.pos[0] - px, it.pos[1] - py);
        const chase = focusBoss ? (v >= 9 || di < 120) : (v >= 9 || di < 260);
        if (chase) {
          desX = it.pos[0] + it.vel[0] * 4;
          desY = clamp(it.pos[1] + it.vel[1] * 4, 200, H - 55);
        }
      }
      if (boss) {
        const floorY = boss.pos[1] + boss.size[1] / 2 + 60;
        desY = Math.max(desY, Math.min(floorY, H - 70));
      }
      desX = clamp(desX, 55, W - 55);
      desY = clamp(desY, 90, H - 45);

      // ----- candidate trajectories -----
      const cands = [{ vx: 0, vy: 0, dur: 1 }];
      const gx = desX - px, gy = desY - py;
      const gd = Math.hypot(gx, gy);
      if (gd > 1) {
        const s = Math.min(cap, gd);
        cands.push({ vx: (gx / gd) * s, vy: (gy / gd) * s, dur: Math.min(3, Math.ceil(gd / s)) });
        const s2 = Math.min(14, gd);
        cands.push({ vx: (gx / gd) * s2, vy: (gy / gd) * s2, dur: 2 });
      }
      const DIRS = 16;
      for (let i = 0; i < DIRS; i++) {
        const a = (2 * Math.PI * i) / DIRS;
        const ca = Math.cos(a), sa = Math.sin(a);
        cands.push({ vx: ca * 14, vy: sa * 14, dur: 2 });
        cands.push({ vx: ca * 40, vy: sa * 40, dur: 1 });
        cands.push({ vx: ca * 40, vy: sa * 40, dur: 3 });
      }

      let bestMove = [0, 0], bestScore = -Infinity;
      for (const c of cands) {
        let x = px, y = py, risk = 0;
        for (let t = 0; t < HORIZON; t++) {
          let vx = 0, vy = 0;
          if (t < c.dur) {
            vx = c.vx; vy = c.vy;
            // respect walls in the swept segment
            const nx = clamp(x + vx, playerR, W - playerR);
            const ny = clamp(y + vy, playerR, H - playerR);
            vx = nx - x; vy = ny - y;
          }
          risk += riskSwept(x, y, vx, vy, t, hazards, playerR);
          x += vx; y += vy;
          if (risk > 1e7) break;
        }
        let s = -risk;
        s -= Math.abs(x - desX) * 1.15;
        s -= Math.abs(y - desY) * 0.7;
        const wallX = Math.min(x, W - x), wallY = Math.min(y, H - y);
        if (wallX < 60) s -= (60 - wallX) * 2.0;
        if (wallY < 40) s -= (40 - wallY) * 1.5;
        if (y < 90) s -= (90 - y) * 3;
        if (wallX + wallY < 120) s -= (120 - wallX - wallY) * 2.5;
        s -= Math.abs(x - W / 2) * 0.12; // mild centerward bias
        if (s > bestScore) { bestScore = s; bestMove = [c.vx, c.vy]; }
      }

      return { action: { move: bestMove, upgrade_choice }, mem: m };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem: mem };
    }
  },
};

