          // strong penalty for ending above the boss's bottom edge
          const bossBottom = boss.pos[1] + boss.size[1] / 2;
          if (y < bossBottom + 30) s -= (bossBottom + 30 - y) * 2.2;
        }
        if (s > bestScore) { bestScore = s; bestMove = [c.vx, c.vy]; }
      }

      return { action: { move: bestMove, upgrade_choice }, mem: m };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem: mem };
    }
  },
};

