  init() {
    return { dmgSeen: 1000, streamSeen: 1, lastVx: 0, lastVy: 0 };
  },

  policy(obs, mem) {
    try {
      const m = mem && typeof mem === "object" ? mem : { dmgSeen: 1000, streamSeen: 1, lastVx: 0, lastVy: 0 };
      const upgrade_choice = chooseUpgrade(obs);
      const p = obs.player;
