"use strict";
// Do enemy bullets fly straight? Track per-bullet velocity changes over life.
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 1);
const maxSteps = Number(process.argv[3] || 12000);

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

const tracks = new Map(); // id -> { v0, vPrev, ticks, maxTurn, maxAccel }
let curving = 0, straight = 0, accel = 0;
const samples = [];

for (let step = 0; step < maxSteps; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  const r = env.step(out.action);
  obs = r.obs;
  for (const o of obs.objects) {
    if (o.type !== "enemy_bullet") continue;
    const tr = tracks.get(o.id);
    if (!tr) {
      tracks.set(o.id, { v0: o.vel.slice(), vPrev: o.vel.slice(), ticks: 0, maxDV: 0 });
    } else {
      tr.ticks++;
      const dvx = o.vel[0] - tr.vPrev[0], dvy = o.vel[1] - tr.vPrev[1];
      const dv = Math.hypot(dvx, dvy);
      if (dv > tr.maxDV) tr.maxDV = dv;
      tr.vPrev = o.vel.slice();
    }
  }
  if (r.done) break;
}

let n = 0, totMaxDV = 0, numChanged = 0, maxObserved = 0;
for (const [, tr] of tracks) {
  if (tr.ticks < 10) continue;
  n++;
  totMaxDV += tr.maxDV;
  if (tr.maxDV > 0.05) numChanged++;
  if (tr.maxDV > maxObserved) maxObserved = tr.maxDV;
}
console.log(`bullets tracked >=10 ticks: ${n}`);
console.log(`changed velocity (>0.05/tick): ${numChanged} (${(numChanged / Math.max(1, n) * 100).toFixed(1)}%)`);
console.log(`mean max |dv|: ${(totMaxDV / Math.max(1, n)).toFixed(4)} px/tick^2, max: ${maxObserved.toFixed(3)}`);

