"use strict";
// Frame-by-frame analysis of the ticks around EHP losses: what hit us, and what did
// the policy's own risk model think of the chosen move?
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 88);
const maxSteps = Number(process.argv[3] || 90000);
const verboseFrom = Number(process.argv[4] || -1); // print all steps from here

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

let lastEhp = obs.player.hp + obs.player.shield_hp;
let prevObs = obs;
let prevAction = null;
const window = []; // ring buffer of recent steps

for (let step = 0; step < maxSteps; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  prevObs = obs;
  prevAction = out.action;
  const r = env.step(out.action);
  obs = r.obs;
  const ehp = obs.player.hp + obs.player.shield_hp;

  window.push({ step, prevPlayer: prevObs.player.pos.slice(), action: prevAction.move.slice(), newPlayer: obs.player.pos.slice() });
  if (window.length > 6) window.shift();

  if (ehp < lastEhp - 1 || step >= verboseFrom && verboseFrom >= 0) {
    console.log(`\n=== EHP ${lastEhp} -> ${ehp} at step ${step} (t=${Math.round(obs.time_ms/1000)}s) ===`);
    console.log("recent moves:", window.map(w => `[${w.action.map(v=>Math.round(v))}]`).join(" "));
    const px0 = prevObs.player.pos[0], py0 = prevObs.player.pos[1];
    const px1 = obs.player.pos[0], py1 = obs.player.pos[1];
    console.log(`player: [${px0.toFixed(1)},${py0.toFixed(1)}] -> [${px1.toFixed(1)},${py1.toFixed(1)}] size=${prevObs.player.size} move req=[${prevAction.move.map(v=>v.toFixed(1))}]`);
    // hazards near (from prev obs), with where they went
    const cur = new Map(obs.objects.map(o => [o.id, o]));
    const rows = [];
    for (const o of prevObs.objects) {
      if (o.type !== "enemy_bullet" && o.type !== "enemy" && o.type !== "enemy_elite" && o.type !== "boss") continue;
      const d = Math.hypot(o.pos[0] - px0, o.pos[1] - py0);
      if (d > 130) continue;
      const now = cur.get(o.id);
      rows.push({
        id: o.id, type: o.type === "enemy_bullet" ? "eb" : o.type, d: Math.round(d),
        pos: o.pos.map(v => Math.round(v)), vel: o.vel.map(v => Math.round(v * 10) / 10),
        size: o.size.map(v => Math.round(v)),
        nowPos: now ? now.pos.map(v => Math.round(v)) : "GONE",
      });
    }
    rows.sort((a, b) => a.d - b.d);
    for (const row of rows.slice(0, 10)) console.log("  ", JSON.stringify(row));
  }
  lastEhp = ehp;
  if (r.done) { console.log(`\nDONE @${step}: ${JSON.stringify({ reason: r.reward_info.done_reason, hp: r.reward_info.hp, progress: r.reward_info.progress })}`); break; }
}

