"use strict";
/**
 * Roguelike Skies policy v7.
 * - Swept-collision (CCD) dodging over a 20-tick horizon; collision >> goal in cost.
 * - Altitude discipline only when the boss rides high; lateral escape preference.
 * - Upgrades: DPS multipliers + exp engine early; shield ensured; bullet_crush prized.
 */

function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

// ---------- upgrades ----------
const UPGRADE_SCORE = {
  ms_split_l: 120, ms_split_m: 110, ms_split_s: 100,
  fr_turbo: 92, fr_cool: 85, fr_basic: 80,
  mix_perfect: 95, mix_vulcan: 88, mix_terminal: 86, mix_fire: 72,
  dmg_l: 84, dmg_m: 78, dmg_s: 70,
  crit_lethal: 76, crit_aim: 74,
  boss_hunter: 90,
  sat_orbit: 65,
  pc_pierce: 66,
  bs_size_s: 56, bs_size_m: 58,
