      m.strafeT = (m.strafeT || 0) + 1;
      if (m.strafeT > 200) { m.strafeT = 0; m.strafeDir = -(m.strafeDir || 1); }
      if (boss && boss.in_cutscene) {
        desX = W / 2; desY = H - 110;
      } else if (bossLive && focusBoss) {
        const bw = boss.size[0];
        const overlapDist = clamp(bw * 3.2, 200, 330);
        const sweep = (m.strafeDir || 1) * bw * 0.4;
        desX = boss.pos[0] + boss.vel[0] * 6 + sweep;
        desY = clamp(boss.pos[1] + boss.size[1] / 2 + overlapDist, 380, H - 90);
      } else {
        const t = pickEnemyTarget(obs);
        if (t) { desX = t.x; desY = H - 130; }
        else if (bossLive) {
          const bw = boss.size[0];
          const sweep = (m.strafeDir || 1) * bw * 0.4;
          desX = boss.pos[0] + boss.vel[0] * 6 + sweep;
          desY = clamp(boss.pos[1] + boss.size[1] / 2 + clamp(bw * 3.2, 200, 330), 380, H - 90);
        } else { desX = W / 2; desY = H - 130; }
      }
