      m.wallTicks = nearWallNow ? (m.wallTicks || 0) + 1 : Math.max(0, (m.wallTicks || 0) - 2);

      // --- DPS proxy ---
      const spawnedSet = new Set(obs.spawned || []);
      let streams = 0;
      for (const o of obs.objects) {
