          desX = boss.pos[0] + boss.vel[0] * 6 + sweep;
          desY = clamp(boss.pos[1] + boss.size[1] / 2 + clamp(bw * 3.2, 200, 330), 380, H - 90);
        } else { desX = W / 2; desY = H - 130; }
