"use strict";
// Batch evaluation with rich diagnostics. Usage: node eval_batch.js [seedlist]
const { RogueEnv } = require("./env.bundle.js");
const path = require("path");

const policyPath = process.argv[3] || "./policy.js";
const seeds = (process.argv[2] || "1,11,23,42,57,88,101,137,199,256,314,451,512").split(",").map(Number);

function runSeed(seed) {
  delete require.cache[require.resolve(path.resolve(policyPath))];
  const policyMod = require(path.resolve(policyPath));
  const env = new RogueEnv();
  let mem = policyMod.init ? policyMod.init() : {};
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
  let lastEhp = obs.player.hp + obs.player.shield_hp;
  const hits = [];
  let lvl90 = 0, lvl180 = 0, lvl300 = 0;
  let bossKills = [];
  let lastBossHp = null, lastBossVariant = null;
  let r = null;
  for (let step = 0; step < 90005; step++) {
    let out;
    try { out = policyMod.policy(obs, mem); } catch (e) { return { seed, error: String(e) }; }
    mem = out.mem;
    r = env.step(out.action);
    obs = r.obs;
    const ehp = obs.player.hp + obs.player.shield_hp;
    if (ehp < lastEhp - 1) {
      const px = obs.player.pos[0], py = obs.player.pos[1];
      const W = obs.field.w, H = obs.field.h;
      hits.push({
        step, t: Math.round(obs.time_ms / 1000), amt: lastEhp - ehp,
        wall: Math.min(px, W - px) < 50, floor: py > H - 60, high: py < 200,
      });
    }
    lastEhp = ehp;
    if (obs.time_ms <= 90500 ) lvl90 = obs.player.level;
    if (obs.time_ms <= 180500) lvl180 = obs.player.level;
    if (obs.time_ms <= 300500) lvl300 = obs.player.level;
    const boss = obs.objects.find(o => o.type === "boss");
    if (boss && !boss.in_cutscene) { lastBossHp = boss.hp; lastBossVariant = boss.variant; }
    if (r.event && r.event.kind === "boss_phase" && r.event.first_sight && bossKills.length === 0 && lastBossVariant && r.event.variant !== lastBossVariant) {
      // a new boss appeared -> previous died
    }
    if (r.done) break;
  }
  const ri = r.reward_info;
  return {
    seed, done: ri.done_reason, win: !!ri.boss_cleared, step: ri.steps,
    progress: ri.progress, level: ri.level, kills: ri.kills,
    t: Math.round(ri.survived_ms / 1000),
    hits: hits.length,
    wallHits: hits.filter(h => h.wall).length,
    floorHits: hits.filter(h => h.floor).length,
    highHits: hits.filter(h => h.high).length,
    dmgTaken: hits.reduce((a, b) => a + b.amt, 0),
    lvl90, lvl180, lvl300,
  };
}

const results = seeds.map(runSeed);
let wins = 0, evalSum = 0;
console.log("seed | result   | step  | prog | lvl(90/180/300/end) | kills | hits (wall/floor/high) | dmg");
for (const r of results) {
  if (r.error) { console.log(`${String(r.seed).padStart(4)} | ERROR ${r.error}`); continue; }
  const evalScore = r.win ? 1 + (90000 - r.step) / 90000 : r.progress;
  evalSum += evalScore;
  if (r.win) wins++;
  console.log(
    `${String(r.seed).padStart(4)} | ${r.win ? "WIN     " : (r.done || "").padEnd(8)} | ${String(r.step).padStart(5)} | ${(r.progress * 100).toFixed(0).padStart(3)}% | ` +
    `${String(r.lvl90).padStart(2)}/${String(r.lvl180).padStart(2)}/${String(r.lvl300).padStart(2)}/${String(r.level).padStart(2)} | ${String(r.kills).padStart(5)} | ` +
    `${String(r.hits).padStart(3)} (${r.wallHits}/${r.floorHits}/${r.highHits}) | ${r.dmgTaken}`
  );
}
console.log(`\nwins ${wins}/${results.length}   mean eval_score ${(evalSum / results.length).toFixed(3)}`);

