"use strict";
// Farm efficiency probe: item pickup vs loss, add population, kill rate over time.
const { RogueEnv } = require("./env.bundle.js");
const policyMod = require("./policy.js");

const seed = Number(process.argv[2] || 451);
const maxSteps = Number(process.argv[3] || 30000);

const env = new RogueEnv();
let mem = policyMod.init ? policyMod.init() : {};
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

let itemsSeen = new Map(); // id -> item_type
let collected = 0, lost = 0;
const lostByType = new Map(), seenByType = new Map();
let lastKills = 0;

for (let step = 0; step < maxSteps; step++) {
  const out = policyMod.policy(obs, mem);
  mem = out.mem;
  const prevItems = new Map();
  for (const o of obs.objects) if (o.type === "item") prevItems.set(o.id, o);
  const prevPlayer = obs.player.pos.slice();
  const magnet = obs.player.magnet_range;
  const r = env.step(out.action);
  obs = r.obs;
  for (const id of obs.despawned || []) {
    const it = prevItems.get(id);
    if (!it) continue;
    // collected if it was within magnet+travel of player; lost if it hit the floor
    const d = Math.hypot(it.pos[0] - obs.player.pos[0], it.pos[1] - obs.player.pos[1]);
    const type = it.item_type;
    seenByType.set(type, (seenByType.get(type) || 0) + 1);
    if (it.pos[1] > obs.field.h - 25 && d > magnet + 45) {
      lost++; lostByType.set(type, (lostByType.get(type) || 0) + 1);
    } else {
      collected++;
    }
  }
  if (step % 3000 === 0 && step > 0) {
    const adds = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite");
    const items = obs.objects.filter(o => o.type === "item");
    const ri = obs.reward_info;
    console.log(`@${step} t=${Math.round(obs.time_ms/1000)}s lvl=${ri.level} kills=${ri.kills} (+${ri.kills - lastKills}) ` +
      `adds=${adds.length} items=${items.length} collected=${collected} lost=${lost} magnet=${magnet} p=[${obs.player.pos.map(v=>Math.round(v))}]`);
    lastKills = ri.kills;
  }
  if (r.done) { console.log(`DONE @${step} ${obs.reward_info.done_reason} prog=${obs.reward_info.progress}`); break; }
}
console.log("\nitems seen:", JSON.stringify([...seenByType.entries()]));
console.log("items LOST:", JSON.stringify([...lostByType.entries()]));

