  sat_orbit: 65,
  bs_size_s: 75, bs_size_m: 78,         // longer/wider bullets: more pierce overlap
  elite_hunter: 52,
  bullet_crush: 92,
  exp_quantum: 115, exp_smart: 75, exp_basic: 58,
  mag_hole: 60, mag_well: 48, mag_basic: 44,
