          const sweep = (m.strafeDir || 1) * (bw / 2 + 20);
          desX = boss.pos[0] + boss.vel[0] * 6 + sweep;
          desY = clamp(boss.pos[1] + boss.size[1] / 2 + clamp(bw * 3.2, 200, 330), 360, H - 170);
