        const di = Math.hypot(it.pos[0] - px, it.pos[1] - py);
        const tooHigh = boss ? (it.pos[1] < 250) : (it.pos[1] < 140);
        const chase = (focusBoss ? (v >= 9 || di < 120) : (v >= 9 || di < 260)) && !tooHigh;
        if (chase) {
